CREATE PROCEDURE [dbo].[spProductBrandUpdate] @BrandId INT, @BrandCode NVARCHAR(50), @BrandName NVARCHAR(100), @Description NVARCHAR(500), @LogoUrl NVARCHAR(500), @IsActive BIT, @UpdatedByUserId INT AS BEGIN SET NOCOUNT ON; UPDATE [dbo].[ProductBrand] SET BrandCode=@BrandCode, BrandName=@BrandName, Description=ISNULL(@Description,N''), LogoUrl=ISNULL(@LogoUrl,N''), IsActive=@IsActive, UpdatedByUserId=NULLIF(@UpdatedByUserId,0), UpdatedDate=SYSUTCDATETIME() WHERE BrandId=@BrandId; END;
